   ]
  },
  {
   "step": "propagation",
   "text": "Each gate precedes quoting eligibility; for a pre-launch venture the qualification clock and the harvest clock are the same 12 months, so a 2-quarter serialization consumes the highest-leverage half of the obtainable window",
   "refs": [
    "profile:Stage",
